def login_required(f):
    @functools.wraps(f)
    def wrap(*args, **kwargs):
        if not session.get("ok"):
            if request.path.startswith("/api/"): return jsonify({"error":"未登录"}), 401
            return redirect("/login")
        return f(*args, **kwargs)
    return wrap

