def sf(v):
    try: return round(float(str(v).replace("%","").replace(",","").strip()), 4)
    except: return None

def fetch_spot():
    try:
        import akshare as ak
        df = ak.fund_etf_spot_em()
        r = {}
        for _, row in df.iterrows():
            c = str(row.get("代码","")).strip()
            # 成交额转亿（原始单位为元）
            turnover_raw = sf(row.get("成交额", 0)) or 0
            turnover_yi = round(turnover_raw / 1e8, 4) if turnover_raw > 1e6 else turnover_raw
            # 规模：优先取"规模(亿)"列，否则取"规模"列
            aum_raw = sf(row.get("规模(亿)", row.get("规模")))
            r[c] = {
                "price":    sf(row.get("最新价")),
                "pct_chg":  sf(row.get("涨跌幅")),
                "premium":  sf(row.get("折溢价率")),
                "turnover": turnover_yi,   # 亿元
                "aum":      aum_raw,
                "fee":      str(row.get("手续费", row.get("综合费率",""))),
            }
        return r
    except Exception as e:
        print(f"[spot] {e}"); return {}

def fetch_index_perf(code):
    # 港股和海外指数 AKShare 不支持，跳过
    if not code or code.startswith(('HS','DJI','SPH','CNI')):
        return None
    try:
        import akshare as ak, pandas as pd
        end = date.today()
        df = ak.index_zh_a_hist(
            symbol=code, period="daily",
            start_date=end.replace(year=end.year-1).strftime("%Y%m%d"),
            end_date=end.strftime("%Y%m%d"),
        )
        if df is None or df.empty: return None
        df = df.sort_values("日期")
        c = df["收盘"].values
        def r(n): return round((c[-1]/c[-n]-1)*100,2) if len(c)>=n else None
        roll = pd.Series(c).cummax()
        dd = round(((pd.Series(c)-roll)/roll).min()*100,2)
        mi = pd.Series(c).idxmin()
        bounce = round((c[-1]/c[mi]-1)*100,2) if mi<len(c)-1 else 0
        return {"ret_1m":r(22),"ret_3m":r(63),"ret_6m":r(126),"ret_1y":r(252),
                "max_dd":dd,"bounce":bounce,"price":round(float(c[-1]),2)}
    except: return None

def fetch_index_cons(index_code, index_name=""):
    # 港股/海外指数暂不支持成分股拉取
    if not index_code or index_code.startswith(('HS','DJI','SPH','CNI')):
        return {"error": "港股/海外指数成分股需从官网查询", "top10": [], "industries": []}
    """
    拉指数成分股权重和行业分布
    支持中证（csindex）和国证（cnindex）
    """
    try:
        import akshare as ak
        df = None

        # 方式1：中证指数成分股权重接口
        try:
            df = ak.index_stock_cons_weight_csindex(symbol=index_code)
        except: pass

        # 方式2：通用成分股接口
        if df is None or df.empty:
            try:
                df = ak.index_stock_cons(symbol=index_code)
            except: pass

        if df is None or df.empty:
            return {}

        # 统一列名
        col_map = {
            "成分券代码":"code","成分券名称":"name",
            "权重":"weight","权重(%)":"weight",
            "股票代码":"code","股票名称":"name",
        }
        df = df.rename(columns={k:v for k,v in col_map.items() if k in df.columns})

        if "weight" not in df.columns:
            df["weight"] = 1.0 / len(df) * 100  # 等权估算

        # 转数字
        df["weight"] = pd.to_numeric(df["weight"].astype(str).str.replace("%",""), errors="coerce").fillna(0)
        df = df.sort_values("weight", ascending=False)

        # 前10大成分股
        top10 = []
        for _, row in df.head(10).iterrows():
            top10.append({
                "name": str(row.get("name","")),
                "code": str(row.get("code","")),
                "weight": round(float(row.get("weight",0)), 2),
            })

        # 行业分布（从成分股申万行业聚合）
        industries = fetch_industry_from_cons(df)

        return {
            "top10": top10,
            "industries": industries,
            "date": date.today().strftime("%Y-%m-%d"),
            "total": len(df),
        }
    except Exception as e:
        print(f"[cons] {index_code}: {e}")
        return {}

def fetch_industry_from_cons(cons_df):
    """从成分股列表聚合行业分布（用申万行业）"""
    try:
        import akshare as ak, pandas as pd
        # 取前30大成分股的行业（太多会很慢）
        codes = cons_df.head(30)["code"].tolist()
        weights = dict(zip(cons_df["code"], cons_df["weight"]))

        industry_weight = {}
        for code in codes[:20]:
            try:
                info = ak.stock_individual_info_em(symbol=code)
                if info is not None and not info.empty:
                    sw = info[info.iloc[:,0]=="行业"].iloc[0,1] if not info[info.iloc[:,0]=="行业"].empty else ""
                    if sw:
                        w = weights.get(code, 0)
                        industry_weight[sw] = industry_weight.get(sw,0) + w
                time.sleep(0.05)
            except: pass

        result = [{"name":k,"weight":round(v,2)} for k,v in sorted(industry_weight.items(), key=lambda x:-x[1])]
        return result[:8]
    except:
        return []

def fetch_all_data():
    with LOCK: CACHE["status"]="loading"; CACHE["error"]=""
    try:
        import akshare as ak

        # 1. ETF实时行情
        print("[1/3] ETF行情...")
        spot = fetch_spot()
        print(f"      {len(spot)}只")

        # 2. 同业排名（从spot聚合）
        print("[2/3] 同业排名...")
        peer_aum = {}
        for idx_name, entries in INDEX_TO_CODES.items():
            peers = []
            for e in entries:
                c = e["code"]
                sp = spot.get(c,{})
                peers.append({"code":c,"name":e["name"],"manager":e["manager"],
                              "aum":sp.get("aum"),"premium":sp.get("premium"),
                              "pct_chg":sp.get("pct_chg")})
            peers.sort(key=lambda x: x["aum"] or 0, reverse=True)
            peer_aum[idx_name] = peers

        # 3. 指数历史行情（并发，只拉A股指数）
        print("[3/3] 指数历史...")
        a_index_codes = {v for k,v in INDEX_CODE_MAP.items()
                        if not v.startswith(('HS','DJI','SPH'))}
        index_perf = {}
        with ThreadPoolExecutor(max_workers=6) as ex:
            futs = {ex.submit(fetch_index_perf, ic): ic for ic in list(a_index_codes)[:35]}
            for fut in as_completed(futs):
                ic = futs[fut]
                r = fut.result()
                if r: index_perf[ic] = r
        print(f"      {len(index_perf)}个指数")

        with LOCK:
            CACHE["spot"] = spot
            CACHE["peer_aum"] = peer_aum
            CACHE["index_perf"] = index_perf
            CACHE["last_update"] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
            CACHE["status"] = "ok"
        print("[完成]")

    except Exception as e:
        with LOCK: CACHE["status"]="error"; CACHE["error"]=str(e)
        print(f"[错误] {e}")

def fetch_index_detail_realtime(index_name, index_code):
    """按需实时拉单个指数的成分股详情"""
    if not index_code or index_code.startswith(('HS','DJI','SPH')):
        return {}
    with LOCK:
        cached = CACHE["index_cons"].get(index_code)
        # 缓存1小时内有效
        if cached and cached.get("date") == date.today().strftime("%Y-%m-%d"):
            return cached
    result = fetch_index_cons(index_code, index_name)
    if result:
        with LOCK:
            CACHE["index_cons"][index_code] = result
    return result

def get_dynamic_peers(idx_name, own_code):
    with LOCK: peers = CACHE["peer_aum"].get(idx_name, [])
    return [p for p in peers if p.get("code") != own_code and p.get("aum")][:2]

