# 自动刷新调度（每天15:30）
# ══════════════════════════════════════════
def _scheduler():
    import schedule
    schedule.every().monday.at("15:30").do(fetch_all_data)
    schedule.every().tuesday.at("15:30").do(fetch_all_data)
    schedule.every().wednesday.at("15:30").do(fetch_all_data)
    schedule.every().thursday.at("15:30").do(fetch_all_data)
    schedule.every().friday.at("15:30").do(fetch_all_data)
    while True:
        schedule.run_pending()
        time.sleep(60)

